class InvoiceService {
  calculateTax(order: Order): number {
    const region = order.getCustomer().getAddress().getRegion();
    const taxClass = order.getCustomer().getAccount().getTaxClass();
    const exemptId = order.getCustomer().getTaxExemption().getId();

    return TaxEngine.compute(region, taxClass, exemptId);
  }
}

class CheckoutService {
  processPayment(cart: ShoppingCart): Receipt {
    const cardNumber = cart
      .getUser()
      .getPaymentProfile()
      .getDefaultCard()
      .getLastFour();

    const amount = cart.getTotalPrice();
    return this.gateway.charge(cardNumber, amount);
  }
}

